import numpy as np


class ArrComparator:
    def __init__(self, tol=1e-6):
        self.tol = tol

    def equal(self, a, b):
        # BUG: uses == which returns elementwise bool array
        return a == b

    def shape_ok(self, a, b):
        return a.shape == b.shape


def test_equal():
    a = np.array([1, 2, 3])
    b = np.array([1, 2, 3])
    cmp = ArrComparator()
    # BUG: ambiguous truth value
    assert cmp.equal(a, b), 'arrays differ'


if __name__ == '__main__':
    test_equal()
